template <class T, class U>
inline bool chmin(T& a, U b) {
	if (a > b) {
		a = b;
		return true;
	}
	return false;
}
template <class T, class U>
inline bool chmax(T& a, U b) {
	if (a < b) {
		a = b;
		return true;
	}
	return false;
}

struct UnionFind {
	int N;
	vector<int> par, siz;
	int find(int x) { return (par[x] == x ? x : par[x] = find(par[x])); }
	void merge(int x, int y) {
		x = find(x), y = find(y);
		if (x == y) return;
		if (siz[x] > siz[y]) swap(x, y);
		par[x] = y;
		siz[y] += siz[x];
	}
	UnionFind(int N) : N(N), siz(N, 1), par(N) {
		iota(par.begin(), par.end(), 0);
	}
};

// 方向を表す
int dx[] = { -1, 0, 1, 0 }, dy[] = { 0, 1, 0, -1 };

// 操作
struct Act {
	int type, x, y;
};

struct Game {
	vector<vector<bool>> C;
	vector<vector<bool>> wall_hrz, wall_vert;
	vector<int> X, Y, wall_used, score;
	bool is_finished = false;

	int MAX_WALL = 10;
	int turn = 0;
	vector<Act> acts;

	// 連結性が保たれているかの判定
	bool isConnected() {
		UnionFind uf(81);
		for (int i = 0; i < 9; i++) {
			for (int j = 0; j < 9; j++) {
				if (i < 8 && !wall_hrz[i][j]) uf.merge(i * 9 + j, (i + 1) * 9 + j);
				if (j < 8 && !wall_vert[i][j]) uf.merge(i * 9 + j, i * 9 + j + 1);
			}
		}
		return (uf.siz[uf.find(0)] == 81);
	}

	// 距離
	double Nearest(int turn) {
		vector<vector<int>> dist(9, vector<int>(9, 10000));
		queue<pair<int, int>> Q;
		Q.push(make_pair(X[turn], Y[turn])); dist[X[turn]][Y[turn]] = 0;
		while (!Q.empty()) {
			int px = Q.front().first;
			int py = Q.front().second; Q.pop();
			if (px >= 1 && !wall_hrz[px - 1][py] && dist[px - 1][py] == 10000) { dist[px - 1][py] = dist[px][py] + 1; Q.push(make_pair(px - 1, py)); }
			if (px <= 7 && !wall_hrz[px + 0][py] && dist[px + 1][py] == 10000) { dist[px + 1][py] = dist[px][py] + 1; Q.push(make_pair(px + 1, py)); }
			if (py >= 1 && !wall_vert[px][py - 1] && dist[px][py - 1] == 10000) { dist[px][py - 1] = dist[px][py] + 1; Q.push(make_pair(px, py - 1)); }
			if (py <= 7 && !wall_vert[px][py + 0] && dist[px][py + 1] == 10000) { dist[px][py + 1] = dist[px][py] + 1; Q.push(make_pair(px, py + 1)); }
		}

		// 列挙
		double val = 0.0;
		for (int i = 0; i < 9; i++) {
			for (int j = 0; j < 9; j++) {
				if (C[i][j] == true) val += exp(-1.0 * dist[i][j]);
			}
		}
		return val;
	}

	// 操作が適正であるかの判定
	bool isOK(Act act) {
		if (act.type == 0) {
			if (act.x == 0) return (X[turn] && !wall_hrz[X[turn] - 1][Y[turn]]);
			if (act.x == 1) return (Y[turn] != 8 && !wall_vert[X[turn]][Y[turn]]);
			if (act.x == 2) return (X[turn] != 8 && !wall_hrz[X[turn]][Y[turn]]);
			if (act.x == 3) return (Y[turn] && !wall_vert[X[turn]][Y[turn] - 1]);
			return false;
		}
		else if (act.type == 1) {
			if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
			if (wall_used[turn] == MAX_WALL)
				return false;  // 11 回目に置こうとしたらアウト
			if (wall_hrz[act.x][act.y] ||
				wall_hrz[act.x][act.y + 1])  // 既に置かれていたらアウト
				return false;
			wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
			bool res = isConnected();  // 連結性チェック
			wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
			return res;
		}
		else if (act.type == 2) {
			if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
			if (wall_used[turn] == MAX_WALL) return false;
			if (wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y])
				return false;
			wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
			bool res = isConnected();
			wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
			return res;
		}
		else
			return false;
	}

	// 操作の候補
	vector<Act> candidateActs() {
		vector<Act> res;
		for (int i = 0; i < 4; i++) {
			if (isOK(Act{ 0, i, 0 })) res.push_back(Act{ 0, i, 0 });  // 隣接マスへ移動
		}
		for (int i = 0; i < 9; i++) {
			for (int j = 0; j < 9; j++) {
				if (isOK(Act{ 1, i, j })) res.push_back(Act{ 1, i, j });  // 水平方向の壁
				if (isOK(Act{ 2, i, j })) res.push_back(Act{ 2, i, j });  // 垂直方向の壁
			}
		}
		return res;
	}

	// 操作を実行する
	bool applyAct(Act act, bool check = true) {
		if (check && !isOK(act)) return false;
		if (act.type == 0) {  // 隣接マスへ移動
			X[turn] += dx[act.x];
			Y[turn] += dy[act.x];
			if (C[X[turn]][Y[turn]]) {
				score[turn]++;
				C[X[turn]][Y[turn]] = false;
			}
		}
		else if (act.type == 1) {  // 水平方向の壁
			wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
			wall_used[turn]++;
		}
		else {  // 垂直方向の壁
			wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
			wall_used[turn]++;
		}

		// ゲームが終了しているかの判定
		bool flag = false;
		for (int i = 0; i < 9; i++) {
			for (int j = 0; j < 9; j++) {
				if (C[i][j] == true) flag = true;
			}
		}
		if (!flag) is_finished = true;
		acts.push_back(act);

		// 交代
		turn ^= 1;
		return true;
	}

	// スコアや盤面を出力する（デバッグ用）
	void printBoard() {
		cerr << "Score: " << score[0] << " " << score[1] << "\n"
			<< "Wall counter: " << wall_used[0] << " " << wall_used[1] << endl
			<< endl;
		for (int i = 0; i < 9; i++) {
			for (int j = 0; j < 9; j++) {
				if (i == X[0] && j == Y[0] && i == X[1] && j == Y[1]) cerr << " AB";
				else if (i == X[0] && j == Y[0]) cerr << " A ";
				else if (i == X[1] && j == Y[1]) cerr << " B ";
				else {
					if (C[i][j]) cerr << " # ";
					else cerr << " . ";
				}
				if (j < 8) cerr << (wall_vert[i][j] ? " | " : "   ");
			}
			cerr << endl;
			if (i != 8) {
				for (int j = 0; j < 9; j++) {
					if (j) cerr << "   ";
					cerr << (wall_hrz[i][j] ? "---" : "   ");
				}
			}
			cerr << endl;
		}
		cerr << endl;
	}
	Game()
		: C(9, vector<bool>(9)),
		wall_hrz(9, vector<bool>(9)),
		wall_vert(9, vector<bool>(9)),
		X(2),
		Y(2),
		wall_used(2),
		score(2) {
		wall_used[0] = wall_used[1] = 0;
		score[0] = score[1] = 0;
		X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
	}
};

int Time = 0;
int TimeLimit = 0;
int NumLoops = 0;

double Rand() {
	double s = 0, t = 1;
	for (int i = 0; i < 3; i++) {
		t /= 1024.0;
		s += 1.0 * (rand() % 1024) * t;
	}
	return 0.01 * (s - 0.5);
}

pair<double, Act> MiniMax(int dep, int turn, int myturn, Game game) {
	// リターン
	NumLoops += 1;
	if (NumLoops % 100 == 0) {
		if(clock() - Time >= TimeLimit) return make_pair(998244353, Act{ -1, -1, -1 });
	}
	if (dep == 0) {
		double BaseScore = 1.0 * (game.score[myturn] - game.score[1 - myturn]);
		double DST1 = game.Nearest(myturn);
		double DST2 = game.Nearest(1 - myturn);
		BaseScore += DST1;
		BaseScore -= DST2;
		return make_pair(BaseScore + Rand(), Act{ -1, -1, -1 });
	}

	// 動く方法の候補
	vector<Act> Cand;

	// 動く方法の候補を列挙
	if (game.isOK(Act{ 0, 0, 0 }) == true) Cand.push_back(Act{ 0, 0, 0 });
	if (game.isOK(Act{ 0, 1, 0 }) == true) Cand.push_back(Act{ 0, 1, 0 });
	if (game.isOK(Act{ 0, 2, 0 }) == true) Cand.push_back(Act{ 0, 2, 0 });
	if (game.isOK(Act{ 0, 3, 0 }) == true) Cand.push_back(Act{ 0, 3, 0 });

	// 壁を置く方法の候補を列挙
	int cx = game.X[1 - myturn];
	int cy = game.Y[1 - myturn];
	int dx[4] = { 0, 0, 1, 1 };
	int dy[4] = { 0, 1, 0, 1 };
	for (int i = 0; i < 4; i++) {
		int sx = cx + dx[i]; sx--;
		int sy = cy + dy[i]; sy--;
		if (sx < 0 || sy < 0 || sx > 7 || sy > 7) continue;
		if (game.isOK(Act{ 1, sx, sy }) == true) Cand.push_back(Act{ 1, sx, sy });
	}
	for (int i = 0; i < 4; i++) {
		int sx = cx + dx[i]; sx--;
		int sy = cy + dy[i]; sy--;
		if (sx < 0 || sy < 0 || sx > 7 || sy > 7) continue;
		if (game.isOK(Act{ 2, sx, sy }) == true) Cand.push_back(Act{ 2, sx, sy });
	}

	// 深さ優先探索
	double score = -10000; if (turn != myturn) score = 10000;
	Act Optimal = Act{ -1, -1, -1 };
	for (Act act : Cand) {
		Game new_game = game;
		new_game.applyAct(act);
		double val = MiniMax(dep - 1, !turn, myturn, new_game).first;
		if (val >= 1.0e8) return make_pair(998244353, Act{ -1, -1, -1 });
		if (turn == myturn && score < val) { score = val; Optimal = act; }
		if (turn != myturn && score > val) { score = val; Optimal = act; }
	}
	return make_pair(score, Optimal);
}

Act choose(int TurnNum, Game game) {
	Time = clock();
	NumLoops = 0;
	if (TurnNum <= 30) TimeLimit = 15 * CLOCKS_PER_SEC / 10;
	else if (TurnNum <= 60) TimeLimit = 10 * CLOCKS_PER_SEC / 10;
	else if (TurnNum <= 90) TimeLimit = 6 * CLOCKS_PER_SEC / 10;
	else TimeLimit = 4 * CLOCKS_PER_SEC / 10;

	int DepCnt = 0;
	pair<double, Act> FinalAct = make_pair(-1, Act{ -1, -1, -1 });
	for (int i = 1; i <= 30; i++) {
		pair<double, Act> ret = MiniMax(i, game.turn, game.turn, game);
		if (ret.first >= 1e8) break;
		FinalAct = ret; DepCnt = i;
		//printf("Turn% 4d: Dep =% 3d, Predict =% 3d, Act = (%d, %d, %d)\n", TurnNum, DepCnt, (int)(FinalAct.first + 0.2), FinalAct.second.type, FinalAct.second.x, FinalAct.second.y);
	}
	return FinalAct.second;
}

Act choose_AI(Game game) {
	vector<Act> acts = game.candidateActs();
	int mx = -1e9;
	Act best_act;
	for (Act act : acts) {
		Game new_game = game;
		new_game.applyAct(act);
		if (chmax(mx, new_game.score[game.turn] - new_game.score[!game.turn])) {
			best_act = act;
		}
	}
	return best_act;
}

int main() {
	int DEBUG = 1;

	// 入力
	string s;
	cin >> s;
	Game game;
	for (int i = 0; i < 9; i++) {
		for (int j = 0; j < 9; j++) {
			char c;
			cin >> c;
			if (c == '#') game.C[i][j] = true;
			else game.C[i][j] = false;
		}
	}

	// ゲーム AI
	int turn = 0, myturn = (s == "First" ? 0 : 1), TotalTurn = 0;
	while (true) {
		if (turn == myturn) {
			Act act = choose(TotalTurn, game);
			game.applyAct(act);
			if (act.type == 0) cout << act.type << " " << act.x << endl;
			if (act.type >= 1) cout << act.type << " " << act.x << " " << act.y << endl;
		}
		else {
			if (DEBUG == 1) {
				int t;
				cin >> t;
				if (t == 0) {
					int x; cin >> x;
					game.applyAct(Act{ 0, x, 0 });
				}
				else if (t <= 2) {
					int x, y; cin >> x >> y;
					game.applyAct(Act{ t, x, y });
				}
				else {
					return 0;
				}
			}
			if (DEBUG == 2) {
				Act act = choose_AI(game);
				game.applyAct(act);
			}
		}
		if (DEBUG == 2 && TotalTurn == 150) break;
		// デバッグ用
		//game.printBoard();
		//cout << game.Nearest(0) << " " << game.Nearest(1) << endl;
		turn ^= 1; TotalTurn += 1;
	}
	return 0;
}
